     Mensualidad\r\n                            </el-button>\r\n                            <!-- <el-button\r\n                                v-if=\"!student.incomplete\"\r\n                                type=\"success\"\r\n                                @click=\"openPayment(student)\"\r\n                            >\r\n                                Mensualidad\r\n                            </el-button> -->\r\n\r\n                            <el-button\r\n                                v-if=\"!student.incomplete\"\r\n                                @click=\"openFormPayments(student)\"\r\n                                type=\"primary\"\r\n                            >\r\n                                Ver tramites\r\n                            </el-button>\r\n                            <el-button\r\n                                v-else\r\n                                @click=\"openFormPayments(student)\"\r\n                                type=\"danger\"\r\n                            >\r\n                                Cancelar pagos\r\n                            </el-button>\r\n                        </div>\r\n                    </td>\r\n                </tr>\r\n            </tbody>\r\n        </table>\r\n        <payment-college\r\n            title=\"Servicio\"\r\n            :is_payment.sync=\"showPayment\"\r\n            @getRecords=\"open\"\r\n            type=\"service\"\r\n            :member.sync=\"member\"\r\n            :classroomId=\"classroomId\"\r\n        ></payment-college>\r\n        <payments-form\r\n            title=\"Tramites\"\r\n            :showDialog.sync=\"showPaymentsForm\"\r\n            :member=\"member\"\r\n            @getRecords=\"getRecords\"\r\n        ></payments-form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nconst PaymentCollege = () => import(\"../../components/payment_college.vue\");\r\nconst PaymentsForm = () => import(\"../../components/payment_form.vue\");\r\nexport default {\r\n    props: [\"showDialog\", \"classroomId\"],\r\n    components: { PaymentCollege, PaymentsForm },\r\n    data() {\r\n        return {\r\n            loading: false,\r\n            students: [],\r\n            allStudents: [],\r\n            description: null,\r\n            showPayment: false,\r\n            member: null,\r\n            showPaymentsForm: false\r\n        };\r\n    },\r\n    methods: {\r\n        getRecords() {},\r\n        openFormPayments(record) {\r\n            this.showPaymentsForm = true;\r\n            this.member = record.member;\r\n        },\r\n        openPayment(record) {\r\n            this.showPayment = true;\r\n            this.member = record.member;\r\n        },\r\n        searchStudent() {\r\n            let desc = this.description.toLowerCase();\r\n            this.students = this.allStudents.filter(s => {\r\n                if (\r\n                    s.name.toLowerCase().includes(desc) ||\r\n                    s.number.toLowerCase().includes(desc)\r\n                ) {\r\n                    return s;\r\n                }\r\n            });\r\n        },\r\n        async open() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/college/classrooms/${this.classroomId}`\r\n                );\r\n\r\n                this.allStudents = response.data;\r\n                this.students = this.allStudents;\r\n                console.log(this.students);\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/College/Resources/assets/js/views/classrooms/student_view.vue","var render = function () {var _vm=this;var _h=_vm.$createElement;var _c=_vm._self._c||_h;return _c('el-dialog',{directives:[{nam